import{_ as o,o as t,c as i,a2 as s}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"How It Works","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/how-it-works.md","filePath":"en/guide/how-it-works.md","lastUpdated":1783223243000}'),n={name:"en/guide/how-it-works.md"};function a(r,e,l,d,c,h){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h1><p>This page walks through CZero&#39;s full path from boot to cleaning, to explain <em>why</em> it&#39;s designed the way it is.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>CZero has no resident Java service. Instead it splits responsibilities into three layers: <strong>install-time</strong> prepares files, <strong>boot-time</strong> starts processes, and <strong>runtime</strong> is a C++ daemon that schedules every task from the config.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Install (customize.sh)  ──►  Boot (service.sh → service)  ──►  Runtime (timer_daemon)</span></span>
<span class="line"><span>   language / inherit         init / fix perms / start daemon    read config.json, schedule</span></span></code></pre></div><h2 id="install-time-customize-sh" tabindex="-1">Install time: customize.sh <a class="header-anchor" href="#install-time-customize-sh" aria-label="Permalink to &quot;Install time: customize.sh&quot;">​</a></h2><p>Runs once during flashing and does three main things:</p><ol><li><strong>Language selection</strong> — reads volume keys via <code>getevent</code>: Volume Up = English, Volume Down = 中文; defaults to Chinese after ~60s of no input. All later prompts use the chosen language.</li><li><strong>Inherit old config</strong> (optional) — if you opt in and a prior install is detected, only the following user data is migrated; everything else resets to the new default: <ul><li><code>list/Emptyfolder/directories.prop</code>, <code>emptyfolder_white.prop</code></li><li><code>list/clean_whitelist.prop</code>, <code>list/clean_paths.prop</code></li><li>the <code>basis/</code> stats directory</li><li>Note: <code>config.json</code> is <strong>not</strong> inherited — it always uses the new default.</li></ul></li><li><strong>Opens the project page</strong> — after install, launches the browser to the GitHub repo.</li></ol><h2 id="boot-time-service-sh-→-service" tabindex="-1">Boot time: service.sh → service <a class="header-anchor" href="#boot-time-service-sh-→-service" aria-label="Permalink to &quot;Boot time: service.sh → service&quot;">​</a></h2><p>Runs on every boot:</p><ol><li><code>service.sh</code> first fixes permissions (dirs 755; <code>.prop</code>/<code>.json</code>/<code>.log</code> etc. 644), starts the <code>service</code> binary, then <code>pkill</code>s the old <code>timer_daemon</code> and relaunches it with <code>setsid</code>.</li><li><code>service</code> (C++): updates <code>module.prop</code>&#39;s <code>description</code> to show current status, creates the <code>basis/basis.prop</code> stats file if missing, and fixes file permissions. It generates <strong>no schedule files</strong> — scheduling is derived entirely by the daemon reading <code>config.json</code>.</li></ol><h2 id="runtime-cron-timer-daemon" tabindex="-1">Runtime: cron/timer_daemon <a class="header-anchor" href="#runtime-cron-timer-daemon" aria-label="Permalink to &quot;Runtime: cron/timer_daemon&quot;">​</a></h2><p>This is the core of CZero — a minimal cron engine built on <code>timerfd</code> + <code>epoll</code>:</p><ul><li><strong>Reads <code>config.json</code> directly</strong> — a built-in JSON parser plus ISO8601→cron conversion builds the job table and gate table in memory, with no intermediate files on disk.</li><li><strong>Hot-reload</strong> — watches <code>config.json</code>&#39;s mtime and rebuilds the job set within a minute on change; if the config is empty or unparseable, it keeps the last-good job set and never interrupts service.</li><li><strong>Fixed daily job</strong> — additionally registers a daily 00:00 <code>list/zero</code> job (reset stats, delete non-today logs) that isn&#39;t in <code>config.json</code>.</li><li><strong>Minute-by-minute</strong> — checks every minute against the phone&#39;s local time (<code>localtime_r</code>); runs scripts via <code>posix_spawn</code>; skips a round if the previous run is still in progress (overlap protection).</li><li><strong>Multi-day gating</strong> — for jobs with a period ≥ 1 day, the last-run timestamp is persisted in <code>cron/state</code>, and the run is skipped if the period hasn&#39;t elapsed.</li><li><strong>Single instance</strong> — a <code>cron/timer.lock</code> file prevents duplicate launches.</li><li><strong>Logging</strong> — writes to the shared daily log (tag <code>[定时]</code>), also gated by <code>general.log</code>.</li></ul><h2 id="how-a-single-cleaning-happens" tabindex="-1">How a single cleaning happens <a class="header-anchor" href="#how-a-single-cleaning-happens" aria-label="Permalink to &quot;How a single cleaning happens&quot;">​</a></h2><p>Take WeChat cache cleaning as an example:</p><ol><li>The daemon triggers <code>list/Tencent/check</code> on schedule.</li><li><code>check</code> identifies the foreground app: reads <code>/dev/cpuset/top-app</code> and <code>dumpsys activity</code>&#39;s <code>ResumedActivity</code>.</li><li>It evaluates safeguards: if the foreground is WeChat itself, or a game → skip this round; otherwise continue.</li><li>It invokes the matching cleaner (<code>tencentmm</code> etc., a Go binary), constrained by <code>enhanced</code> and the temporal barrier.</li><li>It updates <code>basis.prop</code> stats, writes a log if enabled, and can broadcast progress / result to CZeroX.</li></ol><h2 id="why-this-design" tabindex="-1">Why this design <a class="header-anchor" href="#why-this-design" aria-label="Permalink to &quot;Why this design&quot;">​</a></h2><ul><li><strong>No resident service</strong> — woken by the daemon only when needed; otherwise no memory or CPU footprint.</li><li><strong>Single source of truth + hot-reload</strong> — config maps one-to-one to behavior, applies instantly, and a bad config never takes the service down.</li><li><strong>Decoupled native frontend</strong> — CZeroX only reads/writes <code>config.json</code> and is fully decoupled from the module, which runs standalone even without the app.</li></ul>`,19)])])}const u=o(n,[["render",a]]);export{g as __pageData,u as default};
